170	static void
171	fz_trace_path(fz_context *ctx, fz_trace_device *dev, const fz_path *path)
172	{
173		dev->depth++;
174		fz_walk_path(ctx, path, &trace_path_walker, dev);
175		dev->depth--;
176	}
