199	static void
200	fz_trace_stroke_state(fz_context *ctx, fz_output *out, const fz_stroke_state *stroke)
201	{
202		fz_write_printf(ctx, out, " linewidth=\"%g\"", stroke->linewidth);
203		fz_write_printf(ctx, out, " miterlimit=\"%g\"", stroke->miterlimit);
204		fz_write_printf(ctx, out, " linecap=\"%d,%d,%d\"", stroke->start_cap, stroke->dash_cap, stroke->end_cap);
205		fz_write_printf(ctx, out, " linejoin=\"%d\"", stroke->linejoin);
206	
207		if (stroke->dash_len)
208		{
209			int i;
210	
211			fz_write_printf(ctx, out, " dash_phase=\"%g\" dash=\"", stroke->dash_phase);
212			for (i = 0; i < stroke->dash_len; i++)
213				fz_write_printf(ctx, out, "%s%g", i > 0 ? " " : "", stroke->dash_list[i]);
214			fz_write_printf(ctx, out, "\"");
215		}
216	}
