371	static void
372	fz_trace_fill_shade(fz_context *ctx, fz_device *dev_, fz_shade *shade, fz_matrix ctm, float alpha, fz_color_params color_params)
373	{
374		fz_trace_device *dev = (fz_trace_device*)dev_;
375		fz_output *out = dev->out;
376		fz_trace_indent(ctx, out, dev->depth);
377		fz_write_printf(ctx, out, "<fill_shade alpha=\"%g\"", alpha);
378		fz_trace_matrix(ctx, out, ctm);
379		fz_write_printf(ctx, out, " pattern_matrix=\"%g %g %g %g %g %g\"",
380			shade->matrix.a,
381			shade->matrix.b,
382			shade->matrix.c,
383			shade->matrix.d,
384			shade->matrix.e,
385			shade->matrix.f);
386		fz_write_printf(ctx, out, " colorspace=\"%s\"", fz_colorspace_name(ctx, shade->colorspace));
387		fz_trace_color_params(ctx, out, color_params);
388		// TODO: use_background and background
389		// TODO: use_function and function
390		switch (shade->type)
391		{
392		case FZ_FUNCTION_BASED:
393			fz_write_printf(ctx, out, " type=\"function\"");
394			fz_write_printf(ctx, out, " function_matrix=\"%g %g %g %g %g %g\"",
395				shade->u.f.matrix.a,
396				shade->u.f.matrix.b,
397				shade->u.f.matrix.c,
398				shade->u.f.matrix.d,
399				shade->u.f.matrix.e,
400				shade->u.f.matrix.f);
401			fz_write_printf(ctx, out, " domain=\"%g %g %g %g\"",
402				shade->u.f.domain[0][0],
403				shade->u.f.domain[0][1],
404				shade->u.f.domain[1][0],
405				shade->u.f.domain[1][1]);
406			fz_write_printf(ctx, out, " samples=\"%d %d\"",
407				shade->u.f.xdivs,
408				shade->u.f.ydivs);
409			fz_write_printf(ctx, out, "/>\n");
410			break;
411		case FZ_LINEAR:
412			fz_write_printf(ctx, out, " type=\"linear\"");
413			fz_write_printf(ctx, out, " extend=\"%d %d\"",
414				shade->u.l_or_r.extend[0],
415				shade->u.l_or_r.extend[1]);
416			fz_write_printf(ctx, out, " start=\"%g %g\"",
417				shade->u.l_or_r.coords[0][0],
418				shade->u.l_or_r.coords[0][1]);
419			fz_write_printf(ctx, out, " end=\"%g %g\"",
420				shade->u.l_or_r.coords[1][0],
421				shade->u.l_or_r.coords[1][1]);
422			fz_write_printf(ctx, out, "/>\n");
423			break;
424		case FZ_RADIAL:
425			fz_write_printf(ctx, out, " type=\"radial\"");
426			fz_write_printf(ctx, out, " extend=\"%d %d\"",
427				shade->u.l_or_r.extend[0],
428				shade->u.l_or_r.extend[1]);
429			fz_write_printf(ctx, out, " inner=\"%g %g %g\"",
430				shade->u.l_or_r.coords[0][0],
431				shade->u.l_or_r.coords[0][1],
432				shade->u.l_or_r.coords[0][2]);
433			fz_write_printf(ctx, out, " outer=\"%g %g %g\"",
434				shade->u.l_or_r.coords[1][0],
435				shade->u.l_or_r.coords[1][1],
436				shade->u.l_or_r.coords[1][2]);
437			fz_write_printf(ctx, out, "/>\n");
438			break;
439		default:
440			fz_write_printf(ctx, out, " type=\"mesh\"/>\n");
441			break;
442		}
443	}
