474	fz_trace_pop_clip(fz_context *ctx, fz_device *dev_)
475	{
476		fz_trace_device *dev = (fz_trace_device*)dev_;
477		fz_output *out = dev->out;
478		dev->depth--;
479		fz_trace_indent(ctx, out, dev->depth);
480		fz_write_printf(ctx, out, "<pop_clip/>\n");
