604	static const char *
605	metatext_type(fz_metatext meta)
606	{
607		switch (meta)
608		{
609		case FZ_METATEXT_ABBREVIATION:
610			return "abbreviation";
611		case FZ_METATEXT_ACTUALTEXT:
612			return "actualtext";
613		case FZ_METATEXT_ALT:
614			return "alt";
615		case FZ_METATEXT_TITLE:
616			return "title";
617		}
618		return "????";
619	}
