626		const char *type = metatext_type(meta);
627		fz_trace_indent(ctx, out, dev->depth);
628		fz_write_printf(ctx, out, "<metatext type=\"%s\" txt=\"%s\">\n", type, txt ? txt : "");
629		dev->depth++;
630	}
631	
632	static void
633	fz_trace_end_metatext(fz_context *ctx, fz_device *dev_)
