646		fz_output *out = dev->out;
647		fz_trace_indent(ctx, out, dev->depth);
648		fz_write_printf(ctx, out, "<render_flags set=\"0x%x\" clear=\"0x%x\"/>\n", set, clear);
649	}
650	
651	static void
652	fz_trace_set_default_colorspaces(fz_context *ctx, fz_device *dev_, fz_default_colorspaces *dcs)
653	{
654		fz_trace_device *dev = (fz_trace_device*)dev_;
655		fz_output *out = dev->out;
656		fz_trace_indent(ctx, out, dev->depth);
657		fz_write_printf(ctx, out, "<set_default_colorspaces");
658		fz_write_printf(ctx, out, " gray=\"%s\"", fz_colorspace_name(ctx, fz_default_gray(ctx, dcs)));
659		fz_write_printf(ctx, out, " rgb=\"%s\"", fz_colorspace_name(ctx, fz_default_rgb(ctx, dcs)));
660		fz_write_printf(ctx, out, " cmyk=\"%s\"", fz_colorspace_name(ctx, fz_default_cmyk(ctx, dcs)));
661		fz_write_printf(ctx, out, " oi=\"%s\"/>\n",fz_colorspace_name(ctx, fz_default_output_intent(ctx, dcs)));
662	}
663	
664	fz_device *fz_new_trace_device(fz_context *ctx, fz_output *out)
665	{
666		fz_trace_device *dev = fz_new_derived_device(ctx, fz_trace_device);
667	
668		dev->super.fill_path = fz_trace_fill_path;
669		dev->super.stroke_path = fz_trace_stroke_path;
670		dev->super.clip_path = fz_trace_clip_path;
671		dev->super.clip_stroke_path = fz_trace_clip_stroke_path;
672	
673		dev->super.fill_text = fz_trace_fill_text;
674		dev->super.stroke_text = fz_trace_stroke_text;
675		dev->super.clip_text = fz_trace_clip_text;
676		dev->super.clip_stroke_text = fz_trace_clip_stroke_text;
677		dev->super.ignore_text = fz_trace_ignore_text;
678	
679		dev->super.fill_shade = fz_trace_fill_shade;
680		dev->super.fill_image = fz_trace_fill_image;
681		dev->super.fill_image_mask = fz_trace_fill_image_mask;
682		dev->super.clip_image_mask = fz_trace_clip_image_mask;
683	
684		dev->super.pop_clip = fz_trace_pop_clip;
685	
686		dev->super.begin_mask = fz_trace_begin_mask;
687		dev->super.end_mask = fz_trace_end_mask;
688		dev->super.begin_group = fz_trace_begin_group;
689		dev->super.end_group = fz_trace_end_group;
690	
691		dev->super.begin_tile = fz_trace_begin_tile;
692		dev->super.end_tile = fz_trace_end_tile;
693	
694		dev->super.begin_layer = fz_trace_begin_layer;
695		dev->super.end_layer = fz_trace_end_layer;
696	
697		dev->super.begin_structure = fz_trace_begin_structure;
698		dev->super.end_structure = fz_trace_end_structure;
699	
700		dev->super.begin_metatext = fz_trace_begin_metatext;
701		dev->super.end_metatext = fz_trace_end_metatext;
702	
703		dev->super.render_flags = fz_trace_render_flags;
704		dev->super.set_default_colorspaces = fz_trace_set_default_colorspaces;
705	
706		dev->out = out;
707	
708		return (fz_device*)dev;
709	}
