29	static int usage(void)
30	{
31		fprintf(stderr,
32			"usage: mutool trace [options] file [pages]\n"
33			"\t-p -\tpassword\n"
34			"\n"
35			"\t-b -\tuse named page box (MediaBox, CropBox, BleedBox, TrimBox, or ArtBox)\n"
36			"\n"
37			"\t-W -\tpage width for EPUB layout\n"
38			"\t-H -\tpage height for EPUB layout\n"
39			"\t-S -\tfont size for EPUB layout\n"
40			"\t-U -\tfile name of user stylesheet for EPUB layout\n"
41			"\t-X\tdisable document styles for EPUB layout\n"
42			"\n"
43			"\t-d\tuse display list\n"
44			"\n"
45			"\tpages\tcomma separated list of page numbers and ranges\n"
46			);
47		return 1;
48	}
49	
50	static float layout_w = FZ_DEFAULT_LAYOUT_W;
51	static float layout_h = FZ_DEFAULT_LAYOUT_H;
52	static float layout_em = FZ_DEFAULT_LAYOUT_EM;
53	static char *layout_user_css = NULL;
54	static char *layout_user_css_data = NULL;
55	static int layout_publisher_css = 1;
56	static int page_box = FZ_CROP_BOX;
57	
58	static int use_display_list = 0;
59	
60	static void runpage(fz_context *ctx, fz_document *doc, int number)
61	{
62		fz_page *page = NULL;
63		fz_display_list *list = NULL;
64		fz_device *dev = NULL;
65		fz_rect mediabox;
66	
67		fz_var(page);
68		fz_var(list);
69		fz_var(dev);
70		fz_try(ctx)
71		{
72			page = fz_load_page(ctx, doc, number - 1);
73			mediabox = fz_bound_page_box(ctx, page, page_box);
74			printf("<page number=\"%d\" mediabox=\"%g %g %g %g\">\n",
75					number, mediabox.x0, mediabox.y0, mediabox.x1, mediabox.y1);
76			dev = fz_new_trace_device(ctx, fz_stdout(ctx));
77			if (use_display_list)
78			{
79				list = fz_new_display_list_from_page(ctx, page);
80				fz_run_display_list(ctx, list, dev, fz_identity, fz_infinite_rect, NULL);
81			}
82			else
83			{
84				fz_run_page(ctx, page, dev, fz_identity, NULL);
85			}
86			printf("</page>\n");
87		}
88		fz_always(ctx)
89		{
90			fz_drop_display_list(ctx, list);
91			fz_drop_page(ctx, page);
92			fz_drop_device(ctx, dev);
93		}
94		fz_catch(ctx)
95			fz_rethrow(ctx);
96	}
97	
98	static void runrange(fz_context *ctx, fz_document *doc, int count, const char *range)
99	{
100		int start, end, i;
101	
102		while ((range = fz_parse_page_range(ctx, range, &start, &end, count)))
103		{
104			if (start < end)
105				for (i = start; i <= end; ++i)
106					runpage(ctx, doc, i);
107			else
108				for (i = start; i >= end; --i)
109					runpage(ctx, doc, i);
110		}
111	}
112	
113	int mutrace_main(int argc, char **argv)
114	{
115		fz_context *ctx;
116		fz_document *doc = NULL;
117		char *password = "";
118		int i, c, count;
119	
120		while ((c = fz_getopt(argc, argv, "p:b:W:H:S:U:Xd")) != -1)
121		{
122			switch (c)
123			{
124			default: return usage();
125			case 'p': password = fz_optarg; break;
126	
127			case 'W': layout_w = fz_atof(fz_optarg); break;
128			case 'H': layout_h = fz_atof(fz_optarg); break;
129			case 'S': layout_em = fz_atof(fz_optarg); break;
130			case 'U': layout_user_css = fz_optarg; break;
131			case 'X': layout_publisher_css = 0; break;
132	
133			case 'd': use_display_list = 1; break;
134	
135			case 'b':
136				page_box = fz_box_type_from_string(fz_optarg);
137				if (page_box == FZ_UNKNOWN_BOX)
138				{
139					fprintf(stderr, "Invalid box type: %s\n", fz_optarg);
140					return 1;
141				}
142				break;
143			}
144		}
145	
146		if (fz_optind == argc)
147			return usage();
148	
149		ctx = fz_new_context(NULL, NULL, FZ_STORE_UNLIMITED);
150		if (!ctx)
151		{
152			fprintf(stderr, "cannot create mupdf context\n");
153			return EXIT_FAILURE;
154		}
155	
156		fz_try(ctx)
157		{
158			fz_register_document_handlers(ctx);
159			if (layout_user_css)
160				layout_user_css_data = fz_read_text_file(ctx, layout_user_css);
161		}
162		fz_catch(ctx)
163		{
164			fz_report_error(ctx);
165			fprintf(stderr, "cannot initialize mupdf\n");
166			fz_drop_context(ctx);
167			return EXIT_FAILURE;
168		}
169	
170		fz_var(doc);
171		fz_try(ctx)
172		{
173			printf("<?xml version=\"1.0\"?>\n");
174			for (i = fz_optind; i < argc; ++i)
175			{
176				doc = fz_open_document(ctx, argv[i]);
177				if (fz_needs_password(ctx, doc))
178					if (!fz_authenticate_password(ctx, doc, password))
179						fz_throw(ctx, FZ_ERROR_ARGUMENT, "cannot authenticate password: %s", argv[i]);
180				fz_style_document(ctx, doc, layout_publisher_css, layout_user_css_data);
181				fz_layout_document(ctx, doc, layout_w, layout_h, layout_em);
182				printf("<document filename=\"%s\">\n", argv[i]);
183				count = fz_count_pages(ctx, doc);
184				if (i+1 < argc && fz_is_page_range(ctx, argv[i+1]))
185					runrange(ctx, doc, count, argv[++i]);
186				else
187					runrange(ctx, doc, count, "1-N");
188				printf("</document>\n");
189				fz_drop_document(ctx, doc);
190				doc = NULL;
191			}
192		}
193		fz_catch(ctx)
194		{
195			fz_report_error(ctx);
196			fprintf(stderr, "cannot run document\n");
197			fz_drop_document(ctx, doc);
198			fz_free(ctx, layout_user_css_data);
199			fz_drop_context(ctx);
200			return EXIT_FAILURE;
